{
  "name": "ChapterClipper",
  "description": "A local tool to extract, clean, and batch-process webpage chapters into plain text files using Playwright and Cheerio."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Chapter {
  title: string;
  content: string;
  url: string;
  html?: string; // For manual selector mode
}

export interface ExtractionResult {
  status: 'success' | 'failed' | 'pending' | 'processing';
  url: string;
  title?: string;
  filename?: string;
  wordCount?: number;
  error?: string;
  content?: string;
}

export interface SiteTemplate {
  id: string;
  domain: string;
  titleSelector: string;
  contentSelector: string;
  removeSelectors: string[];
  nextPageSelector?: string;
}

export interface AppSettings {
  concurrency: number;
  rateLimit: number; // requests per minute
  outputFolder: string;
  filenamePattern: string; // e.g. "{series}/{vol}/{ch} {title}.txt"
  cleanup: {
    removeImages: boolean;
    smartQuotes: boolean;
    normalizeUnicode: boolean;
  };
}

export interface BatchItem {
  id: string;
  url: string;
  series?: string;
  volume?: string;
  chapterNumber?: string;
  status: 'pending' | 'processing' | 'success' | 'failed';
  result?: ExtractionResult;
  retries: number;
}

import React, { useState } from 'react';
import { HashRouter, Routes, Route, NavLink, useLocation } from 'react-router-dom';
