import React, { useState } from 'react';
import { Play, Copy, Download, Loader2, AlertCircle, FileCheck } from 'lucide-react';
import { Chapter } from '../types';

export default function SingleExtract() {
  const [url, setUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<Chapter | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleExtract = async () => {
    if (!url) return;
    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const response = await fetch('http://localhost:3000/api/extract', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url }),
      });

      if (!response.ok) {
        const errData = await response.json();
        throw new Error(errData.message || 'Extraction failed');
      }

      const data = await response.json();
      setResult(data);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = () => {
    if (result) {
      navigator.clipboard.writeText(`${result.title}\n\n${result.content}`);
    }
  };

  const downloadTxt = () => {
    if (!result) return;
    const element = document.createElement("a");
    const file = new Blob([`${result.title}\n\nSource: ${result.url}\n\n${result.content}`], {type: 'text/plain'});
    element.href = URL.createObjectURL(file);
    element.download = `${result.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.txt`;
    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-2">
        <h2 className="text-2xl font-bold text-gray-900">Single Chapter Extract</h2>
        <p className="text-gray-500">Enter a URL to preview and extract content instantly.</p>
      </div>

      <div className="flex gap-4">
        <input
          type="url"
          value={url}
          onChange={(e) => setUrl(e.target.value)}
          placeholder="https://example.com/novel/chapter-1"
          className="flex-1 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
        />
        <button
          onClick={handleExtract}
          disabled={loading || !url}
          className="bg-blue-600 text-white px-6 py-3 rounded-lg font-medium hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
        >
          {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Play className="w-5 h-5" />}
          Run
        </button>
      </div>

      {error && (
        <div className="bg-red-50 text-red-700 p-4 rounded-lg flex items-center gap-3 border border-red-200">
          <AlertCircle className="w-5 h-5 shrink-0" />
          <p>{error}</p>
        </div>
      )}

      {result && (
        <div className="bg-white border border-gray-200 rounded-xl shadow-sm overflow-hidden">
          <div className="bg-gray-50 px-6 py-4 border-b border-gray-200 flex justify-between items-center sticky top-0">
            <div>
              <h3 className="font-semibold text-gray-900">{result.title}</h3>
              <p className="text-xs text-gray-500 truncate max-w-md">{result.url}</p>
            </div>
            <div className="flex gap-2">
              <button onClick={copyToClipboard} className="p-2 text-gray-600 hover:bg-white hover:text-blue-600 rounded-md transition-colors border border-transparent hover:border-gray-200" title="Copy">
                <Copy className="w-5 h-5" />
              </button>
              <button onClick={downloadTxt} className="p-2 text-gray-600 hover:bg-white hover:text-green-600 rounded-md transition-colors border border-transparent hover:border-gray-200" title="Download">
                <Download className="w-5 h-5" />
              </button>
            </div>
          </div>
          <div className="p-8 max-h-[600px] overflow-y-auto prose prose-slate max-w-none">
            <pre className="whitespace-pre-wrap font-serif text-lg leading-relaxed text-gray-800">
              {result.content}
            </pre>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Layers, Plus, Trash2, Play, Pause, RotateCcw, Download, Loader2, CheckCircle, XCircle } from 'lucide-react';
import { BatchItem } from '../types';

export default function BatchExtract() {
  const [urls, setUrls] = useState('');
  const [queue, setQueue] = useState<BatchItem[]>([]);
  const [processing, setProcessing] = useState(false);
  const [progress, setProgress] = useState({ total: 0, completed: 0, failed: 0 });

  useEffect(() => {
    // Poll for updates if processing
    let interval: NodeJS.Timeout;
    if (processing) {
      interval = setInterval(fetchQueueStatus, 1000);
    }
    return () => clearInterval(interval);
  }, [processing]);

  const fetchQueueStatus = async () => {
    try {
      const res = await fetch('http://localhost:3000/api/batch/status');
      const data = await res.json();
      setQueue(data.queue);
      setProcessing(data.isProcessing);

      const completed = data.queue.filter((i: BatchItem) => i.status === 'success').length;
      const failed = data.queue.filter((i: BatchItem) => i.status === 'failed').length;
      setProgress({ total: data.queue.length, completed, failed });

    } catch (e) {
      console.error("Failed to fetch status", e);
    }
  };

  const addToQueue = () => {
    if (!urls.trim()) return;
    const newItems = urls.split('\n').filter(u => u.trim()).map(url => ({
      id: Math.random().toString(36).substr(2, 9),
      url: url.trim(),
      status: 'pending' as const,
      retries: 0
    }));

    // Sync with backend
    fetch('http://localhost:3000/api/batch/add', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({ items: newItems })
    }).then(fetchQueueStatus);

    setUrls('');
  };

  const startBatch = async () => {
    setProcessing(true);
    await fetch('http://localhost:3000/api/batch/start', { method: 'POST' });
  };

  const stopBatch = async () => {
    setProcessing(false);
    await fetch('http://localhost:3000/api/batch/stop', { method: 'POST' });
  };

  const clearQueue = async () => {
    await fetch('http://localhost:3000/api/batch/clear', { method: 'POST' });
    fetchQueueStatus();
  };

  const downloadZip = () => {
     window.location.href = 'http://localhost:3000/api/batch/download';
  };

  return (
    <div className="space-y-6 h-full flex flex-col">
      <div className="flex justify-between items-start">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Batch Processor</h2>
          <p className="text-gray-500">Queue multiple URLs for background extraction.</p>
        </div>
        <div className="flex gap-2">
           {processing ? (
             <button onClick={stopBatch} className="bg-amber-500 hover:bg-amber-600 text-white px-4 py-2 rounded-lg flex items-center gap-2">
               <Pause className="w-4 h-4" /> Stop
             </button>
           ) : (
             <button onClick={startBatch} disabled={queue.length === 0} className="bg-green-600 hover:bg-green-700 disabled:opacity-50 text-white px-4 py-2 rounded-lg flex items-center gap-2">
               <Play className="w-4 h-4" /> Start Batch
             </button>
           )}
           <button onClick={downloadZip} disabled={progress.completed === 0} className="bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white px-4 py-2 rounded-lg flex items-center gap-2">
             <Download className="w-4 h-4" /> Export All (ZIP)
           </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 flex-1 min-h-0">
        {/* Input Area */}
        <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm flex flex-col gap-4">
          <label className="font-semibold text-gray-700">Add URLs</label>
          <textarea
            className="flex-1 w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 text-sm font-mono"
            placeholder="Paste URLs here, one per line..."
            value={urls}
            onChange={e => setUrls(e.target.value)}
          />
          <button onClick={addToQueue} className="w-full bg-gray-900 text-white py-2 rounded-lg hover:bg-gray-800 flex justify-center items-center gap-2">
            <Plus className="w-4 h-4" /> Add to Queue
          </button>
        </div>

        {/* Queue List */}
        <div className="lg:col-span-2 bg-white rounded-xl border border-gray-200 shadow-sm flex flex-col min-h-0">
          <div className="p-4 border-b border-gray-200 flex justify-between items-center bg-gray-50 rounded-t-xl">
             <div className="flex gap-4 text-sm font-medium text-gray-600">
               <span>Total: {progress.total}</span>
               <span className="text-green-600">Success: {progress.completed}</span>
               <span className="text-red-600">Failed: {progress.failed}</span>
             </div>
             <button onClick={clearQueue} className="text-gray-500 hover:text-red-600">
               <Trash2 className="w-5 h-5" />
             </button>
          </div>
          <div className="flex-1 overflow-y-auto p-0">
            <table className="w-full text-left text-sm">
              <thead className="bg-gray-50 text-gray-500 font-medium border-b border-gray-200 sticky top-0">
                <tr>
                  <th className="px-4 py-3">Status</th>
                  <th className="px-4 py-3">URL / Title</th>
                  <th className="px-4 py-3 text-right">Info</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {queue.map((item) => (
                  <tr key={item.id} className="hover:bg-gray-50">
                    <td className="px-4 py-3 w-24">
                      {item.status === 'pending' && <span className="bg-gray-100 text-gray-600 px-2 py-1 rounded text-xs">Pending</span>}
                      {item.status === 'processing' && <span className="bg-blue-100 text-blue-600 px-2 py-1 rounded text-xs flex w-fit items-center gap-1"><Loader2 className="w-3 h-3 animate-spin"/> Active</span>}
                      {item.status === 'success' && <span className="bg-green-100 text-green-700 px-2 py-1 rounded text-xs flex w-fit items-center gap-1"><CheckCircle className="w-3 h-3"/> Done</span>}
                      {item.status === 'failed' && <span className="bg-red-100 text-red-700 px-2 py-1 rounded text-xs flex w-fit items-center gap-1"><XCircle className="w-3 h-3"/> Error</span>}
                    </td>
                    <td className="px-4 py-3">
                      <div className="font-medium text-gray-900 truncate max-w-xs md:max-w-md">
                        {item.result?.title || item.url}
                      </div>
                      {item.result?.error && <div className="text-xs text-red-500 mt-1">{item.result.error}</div>}
                    </td>
                    <td className="px-4 py-3 text-right text-gray-500">
                      {item.result?.wordCount ? `${item.result.wordCount} words` : '-'}
                    </td>
                  </tr>
                ))}
                {queue.length === 0 && (
                  <tr>
                    <td colSpan={3} className="px-4 py-8 text-center text-gray-400">
                      Queue is empty. Add URLs to start.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { SiteTemplate } from '../types';
import { Plus, Trash, Save, Globe, Code, Check } from 'lucide-react';

export default function Templates() {
  const [templates, setTemplates] = useState<SiteTemplate[]>([]);
  const [editing, setEditing] = useState<Partial<SiteTemplate>>({});
  const [testUrl, setTestUrl] = useState('');
  const [testResult, setTestResult] = useState<{title?: string, contentSnippet?: string} | null>(null);
  const [pickingMode, setPickingMode] = useState(false);
  const [iframeSrc, setIframeSrc] = useState<string | null>(null);

  useEffect(() => {
    fetch('http://localhost:3000/api/templates')
      .then(res => res.json())
      .then(setTemplates);
  }, []);

  const saveTemplate = async () => {
    if (!editing.domain || !editing.titleSelector || !editing.contentSelector) return;

    await fetch('http://localhost:3000/api/templates', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify(editing)
    });

    // Refresh
    const res = await fetch('http://localhost:3000/api/templates');
    setTemplates(await res.json());
    setEditing({});
    setTestResult(null);
  };

  const deleteTemplate = async (id: string) => {
    await fetch(`http://localhost:3000/api/templates/${id}`, { method: 'DELETE' });
    const res = await fetch('http://localhost:3000/api/templates');
    setTemplates(await res.json());
  };

  const testSelectors = async () => {
    if (!testUrl || !editing.titleSelector || !editing.contentSelector) return;

    const res = await fetch('http://localhost:3000/api/extract/test-selectors', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({ 
        url: testUrl, 
        titleSelector: editing.titleSelector,
        contentSelector: editing.contentSelector 
      })
    });
    const data = await res.json();
    setTestResult(data);
  };

  // Helper to load live preview (In a real app this would be more complex due to securities)
  const loadPreview = async () => {
    if(!testUrl) return;
    // We request the backend to proxy the page so we can render it in an iframe
    // and attach listeners. For this MVP, we will assume a "Selector Helper" mode
    // where the user manually types selectors based on the visual feedback.
    setPickingMode(true);
  };

  return (
    <div className="h-full flex flex-col space-y-6">
      <div className="flex justify-between items-center">
        <div>
           <h2 className="text-2xl font-bold text-gray-900">Site Templates</h2>
           <p className="text-gray-500">Define custom CSS selectors for specific domains.</p>
        </div>
        <button onClick={() => setEditing({ id: 'new', removeSelectors: [] })} className="bg-blue-600 text-white px-4 py-2 rounded-lg flex items-center gap-2">
           <Plus className="w-4 h-4" /> New Template
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 flex-1 min-h-0">
        {/* List */}
        <div className="bg-white border border-gray-200 rounded-xl overflow-hidden flex flex-col">
           <div className="p-4 bg-gray-50 border-b border-gray-200 font-medium text-gray-600">Saved Sites</div>
           <div className="flex-1 overflow-y-auto">
             {templates.map(t => (
               <div key={t.id} className="p-4 border-b border-gray-100 hover:bg-gray-50 flex justify-between items-center group">
                 <div>
                   <div className="font-semibold text-gray-800">{t.domain}</div>
                   <div className="text-xs text-gray-500 code">{t.contentSelector}</div>
                 </div>
                 <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                   <button onClick={() => setEditing(t)} className="text-blue-600 p-1 hover:bg-blue-50 rounded"><Code className="w-4 h-4"/></button>
                   <button onClick={() => deleteTemplate(t.id)} className="text-red-600 p-1 hover:bg-red-50 rounded"><Trash className="w-4 h-4"/></button>
                 </div>
               </div>
             ))}
           </div>
        </div>

        {/* Editor */}
        <div className="lg:col-span-2 bg-white border border-gray-200 rounded-xl p-6 overflow-y-auto">
          {editing.id ? (
            <div className="space-y-6">
              <h3 className="text-lg font-bold border-b pb-2 mb-4">
                {editing.id === 'new' ? 'Create Template' : 'Edit Template'}
              </h3>

              <div className="grid grid-cols-1 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Domain (e.g., example.com)</label>
                  <input 
                    type="text" 
                    value={editing.domain || ''} 
                    onChange={e => setEditing({...editing, domain: e.target.value})}
                    className="w-full p-2 border rounded"
                  />
                </div>

                <div className="p-4 bg-blue-50 rounded-lg border border-blue-100">
                  <h4 className="text-sm font-bold text-blue-800 mb-2">Selector Testing</h4>
                  <div className="flex gap-2 mb-2">
                     <input 
                       type="text" 
                       placeholder="Test URL from this domain" 
                       value={testUrl}
                       onChange={e => setTestUrl(e.target.value)}
                       className="flex-1 p-2 border rounded text-sm"
                     />
                     <button onClick={loadPreview} className="bg-white text-blue-600 border border-blue-200 px-3 py-1 rounded hover:bg-blue-50 text-sm">Preview</button>
                  </div>
                  {pickingMode && (
                      <div className="text-xs text-blue-600 mb-2">
                          * In Manual Mode: Open your browser's dev tools (F12) on the target site to copy selectors. Auto-picker not available in this simplified web view.
                      </div>
                  )}
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Title Selector</label>
                    <input 
                      type="text" 
                      value={editing.titleSelector || ''} 
                      onChange={e => setEditing({...editing, titleSelector: e.target.value})}
                      placeholder="h1.entry-title"
                      className="w-full p-2 border rounded font-mono text-sm"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Content Selector</label>
                    <input 
                      type="text" 
                      value={editing.contentSelector || ''} 
                      onChange={e => setEditing({...editing, contentSelector: e.target.value})}
                      placeholder=".chapter-content"
                      className="w-full p-2 border rounded font-mono text-sm"
                    />
                  </div>
                </div>

                <div>
                   <label className="block text-sm font-medium text-gray-700 mb-1">Remove Selectors (comma separated)</label>
                   <input 
                      type="text" 
                      value={editing.removeSelectors?.join(', ') || ''} 
                      onChange={e => setEditing({...editing, removeSelectors: e.target.value.split(',').map(s => s.trim())})}
                      placeholder=".ad-banner, .share-buttons"
                      className="w-full p-2 border rounded font-mono text-sm"
                    />
                </div>

                <div className="flex justify-end gap-2 pt-4">
                   <button onClick={testSelectors} className="px-4 py-2 border rounded hover:bg-gray-50">Test Extract</button>
                   <button onClick={saveTemplate} className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 flex items-center gap-2">
                     <Save className="w-4 h-4" /> Save Template
                   </button>
                </div>

                {testResult && (
                  <div className="mt-4 p-4 bg-gray-50 border rounded text-sm">
                    <p><strong>Found Title:</strong> {testResult.title || <span className="text-red-500">Not found</span>}</p>
                    <p className="mt-2"><strong>Content Preview:</strong></p>
                    <p className="text-gray-600 italic line-clamp-3">{testResult.contentSnippet || 'No content found'}</p>
                  </div>
                )}

              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-gray-400">
               <Globe className="w-12 h-12 mb-2" />
               <p>Select a template to edit or create a new one.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { AppSettings } from '../types';
import { Save } from 'lucide-react';

export default function Settings() {
  const [settings, setSettings] = useState<AppSettings | null>(null);
  const [saved, setSaved] = useState(false);

  useEffect(() => {
    fetch('http://localhost:3000/api/settings')
      .then(res => res.json())
      .then(setSettings);
  }, []);

  const handleSave = async () => {
    if (!settings) return;
    await fetch('http://localhost:3000/api/settings', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify(settings)
    });
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
  };

  if (!settings) return <div>Loading...</div>;

  return (
    <div className="max-w-2xl mx-auto space-y-8">
      <div>
        <h2 className="text-2xl font-bold text-gray-900">Settings</h2>
