import * as cheerio from 'cheerio';
import { Readability } from '@mozilla/readability';
import { JSDOM } from 'jsdom';
import { chromium } from 'playwright';
import { getTemplateForUrl } from './templates';
import { get as getSettings } from './settings';

export async function extractSingle(url: string, templateId?: string) {
  const settings = getSettings();
  let html = '';

  // 1. Fetch
  // Simple fetch first, fallback to Playwright if needed (logic simplified here to just fetch)
  // In a robust app, we'd detect dynamic content requirements or 403s.
  try {
    const res = await fetch(url, { headers: { 'User-Agent': 'Mozilla/5.0' } });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    html = await res.text();
  } catch (e) {
    console.log('Static fetch failed, trying Playwright...');
    const browser = await chromium.launch();
    const page = await browser.newPage();
    await page.goto(url, { waitUntil: 'domcontentloaded' });
    html = await page.content();
    await browser.close();
  }

  // 2. Parse
  const $ = cheerio.load(html);

  // 3. Template vs Auto
  const template = getTemplateForUrl(url); // Ignored templateId arg for auto-match simplicity
  let title = '';
  let content = '';

  if (template) {
    // Manual Mode
    if (template.removeSelectors) {
      template.removeSelectors.forEach(s => $(s).remove());
    }
    title = $(template.titleSelector).first().text();
    // Preserve paragraphs
    const contentEl = $(template.contentSelector).first();
    content = formatContent($, contentEl);
  } else {
    // Auto Mode (Readability)
    const dom = new JSDOM(html, { url });
    const reader = new Readability(dom.window.document);
    const article = reader.parse();
    if (!article) throw new Error('Could not auto-extract content.');

    title = article.title;
    // Readability returns HTML, we need to strip it to clean text but keep paragraphs
    const $auto = cheerio.load(article.content);
    content = formatContent($auto, $auto('body'));
  }

  // 4. Cleanup
  title = cleanText(title, settings);
  content = cleanText(content, settings);

  return { title, content, url };
}

function formatContent($: cheerio.CheerioAPI, el: cheerio.Cheerio<any>): string {
    let textParts: string[] = [];

    // Simple heuristic: iterate p, div, br
    el.find('p, div, h1, h2, h3, h4, h5, h6, li').each((_, elem) => {
        const text = $(elem).text().trim();
        if (text) textParts.push(text);
    });

    // If structured tags aren't found, fallback to generic text
    if (textParts.length === 0) {
        return el.text().trim();
    }

    return textParts.join('\n\n');
}

function cleanText(text: string, settings: any): string {
  if (!text) return '';

  if (settings.cleanup.normalizeUnicode) {
    text = text.normalize('NFKC');
  }

  if (settings.cleanup.smartQuotes) {
    text = text.replace(/[\u2018\u2019]/g, "'").replace(/[\u201C\u201D]/g, '"');
  }

  // Remove excessive whitespace
  return text.replace(/\n{3,}/g, '\n\n').trim();
}

export async function testSelectors(url: string, titleSelector: string, contentSelector: string) {
    // reuse extract logic but enforce selectors
    try {
        const res = await fetch(url, { headers: { 'User-Agent': 'Mozilla/5.0' } });
        const html = await res.text();
        const $ = cheerio.load(html);
        const title = $(titleSelector).first().text().trim();
        const contentEl = $(contentSelector).first();
        const content = contentEl.text().trim().substring(0, 200) + '...';
        return { title, contentSnippet: content };
    } catch(e) {
        return { title: 'Error fetching', contentSnippet: '' };
    }
}

import { BatchItem, ExtractionResult } from '../types'; // This relies on shared logic, in real app, separate
import * as extractor from './extractor';
import * as settings from './settings';
import AdmZip from 'adm-zip';
import sanitize from 'sanitize-filename';

// Re-defining interface locally for strictness if types.ts isn't shared easily in XML structure
interface QueueItem {
    id: string;
    url: string;
    status: 'pending' | 'processing' | 'success' | 'failed';
    result?: any;
    retries: number;
}

let queue: QueueItem[] = [];
let isProcessing = false;

export function getStatus() {
    return { queue, isProcessing };
}

export function addItems(items: QueueItem[]) {
    queue.push(...items);
}

export function clearQueue() {
    if (!isProcessing) queue = [];
}

export async function startProcessing() {
    if (isProcessing) return;
    isProcessing = true;
    processQueue();
}

export function stopProcessing() {
    isProcessing = false;
}

async function processQueue() {
    const config = settings.get();
    const concurrency = config.concurrency || 1;

    while (isProcessing) {
        const pending = queue.find(i => i.status === 'pending');
        if (!pending) break; // Done

        // Super simple concurrency handling: just await one by one for this demo
        // To do real concurrency, we'd need a pool.

        pending.status = 'processing';

        try {
            // Rate limit delay
            const delay = 60000 / (config.rateLimit || 10);
            await new Promise(r => setTimeout(r, delay));

            const result = await extractor.extractSingle(pending.url);
            pending.result = {
                ...result,
                filename: generateFilename(result.title, 'Vol1', '01'), // Simplified
                wordCount: result.content.split(/\s+/).length
            };
            pending.status = 'success';
        } catch (e: any) {
            pending.status = 'failed';
            pending.result = { error: e.message };
            console.error(`Error processing ${pending.url}:`, e);
        }
    }
    isProcessing = false;
}

function generateFilename(title: string, vol: string, ch: string) {
    return sanitize(`${vol}-${ch} ${title}.txt`);
}

export async function createBatchZip() {
    const zip = new AdmZip();
    const successItems = queue.filter(i => i.status === 'success' && i.result);

    successItems.forEach(item => {
        if(item.result) {
            const content = `${item.result.title}\n${item.url}\n\n${item.result.content}`;
            const fname = sanitize(`${item.result.title.substring(0, 50)}.txt`);
            zip.addFile(fname, Buffer.from(content, 'utf8'));
        }
    });

    return zip.toBuffer();
}

import fs from 'fs';
import path from 'path';

// For this XML output, we use a simple JSON file
const DB_FILE = path.resolve('./templates.db.json');

interface Template {
    id: string;
    domain: string;
    titleSelector: string;
    contentSelector: string;
    removeSelectors: string[];
}

let templates: Template[] = [];

try {
    if (fs.existsSync(DB_FILE)) {
        templates = JSON.parse(fs.readFileSync(DB_FILE, 'utf-8'));
    }
} catch (e) {
    console.error("Failed to load templates", e);
}

function saveToDisk() {
    fs.writeFileSync(DB_FILE, JSON.stringify(templates, null, 2));
}

export function getAll() {
    return templates;
}

export function save(template: Template) {
    if (template.id === 'new') {
        template.id = Math.random().toString(36).substr(2, 9);
        templates.push(template);
    } else {
        const idx = templates.findIndex(t => t.id === template.id);
        if (idx >= 0) templates[idx] = template;
    }
    saveToDisk();
}

export function remove(id: string) {
    templates = templates.filter(t => t.id !== id);
    saveToDisk();
}

export function getTemplateForUrl(url: string) {
    try {
        const domain = new URL(url).hostname;
        return templates.find(t => domain.includes(t.domain));
    } catch {
        return null;
    }
}

