import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Play, Pause, Download, Loader2, CheckCircle, XCircle, List, TerminalSquare } from 'lucide-react';
import { BatchItem } from '../types';

export default function BatchExtract() {
  const [urls, setUrls] = useState('');
  const [queue, setQueue] = useState<BatchItem[]>([]);
  const [processing, setProcessing] = useState(false);
  const [progress, setProgress] = useState({ total: 0, completed: 0, failed: 0 });

  useEffect(() => {
    let interval: ReturnType<typeof setInterval>;
    if (processing) {
      interval = setInterval(fetchQueueStatus, 1000);
    }
    return () => clearInterval(interval);
  }, [processing]);

  const fetchQueueStatus = async () => {
    try {
      const res = await fetch('/api/batch/status');
      const data = await res.json();
      setQueue(data.queue);
      setProcessing(data.isProcessing);

      const completed = data.queue.filter((i: BatchItem) => i.status === 'success').length;
      const failed = data.queue.filter((i: BatchItem) => i.status === 'failed').length;
      setProgress({ total: data.queue.length, completed, failed });

    } catch (e) {
      console.error("Failed to fetch status", e);
    }
  };

  const addToQueue = () => {
    if (!urls.trim()) return;
    const newItems = urls.split('\n').filter(u => u.trim()).map(url => ({
      id: Math.random().toString(36).substr(2, 9),
      url: url.trim(),
      status: 'pending' as const,
      retries: 0
    }));

    fetch('/api/batch/add', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({ items: newItems })
    }).then(() => fetchQueueStatus());

    setUrls('');
  };

  const startBatch = async () => {
    setProcessing(true);
    await fetch('/api/batch/start', { method: 'POST' });
  };

  const stopBatch = async () => {
    setProcessing(false);
    await fetch('/api/batch/stop', { method: 'POST' });
  };

  const clearQueue = async () => {
    await fetch('/api/batch/clear', { method: 'POST' });
    fetchQueueStatus();
  };

  const downloadZip = () => {
     window.location.href = '/api/batch/download';
  };

  return (
    <div className="space-y-6 h-full flex flex-col animate-in fade-in duration-500">
      <div className="flex justify-between items-end border-b border-white/10 pb-4">
        <div>
          <h2 className="text-3xl font-bold text-white tracking-tight uppercase flex items-center gap-3">
             <List className="text-katana" /> Batch Processor
          </h2>
          <p className="text-steel font-mono text-xs mt-1 tracking-wider">> AWAITING URL INPUT STREAM</p>
        </div>
        <div className="flex gap-3">
           {processing ? (
             <button onClick={stopBatch} className="bg-yellow-600/20 border border-yellow-600/50 text-yellow-500 hover:bg-yellow-600/30 px-6 py-2 uppercase text-xs font-bold tracking-widest flex items-center gap-2 transition-all">
               <Pause className="w-4 h-4" /> Halt
             </button>
           ) : (
             <button onClick={startBatch} disabled={queue.length === 0} className="bg-katana hover:bg-red-600 text-black px-6 py-2 uppercase text-xs font-bold tracking-widest flex items-center gap-2 transition-all disabled:opacity-30 disabled:cursor-not-allowed">
               <Play className="w-4 h-4 fill-current" /> Engage
             </button>
           )}
           <button onClick={downloadZip} disabled={progress.completed === 0} className="border border-white/20 text-white hover:border-katana hover:text-katana px-6 py-2 uppercase text-xs font-bold tracking-widest flex items-center gap-2 transition-all disabled:opacity-30 disabled:cursor-not-allowed">
             <Download className="w-4 h-4" /> Archive
           </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 flex-1 min-h-0">
        {/* Input Area */}
        <div className="bg-armor border border-white/10 p-1 flex flex-col h-full">
          <div className="bg-white/5 p-3 border-b border-white/5">
             <label className="font-mono text-xs font-bold text-katana uppercase tracking-wider">Input Stream</label>
          </div>
          <textarea
            className="flex-1 w-full p-4 bg-void text-steel focus:outline-none focus:bg-black font-mono text-xs resize-none placeholder:text-gray-800"
            placeholder="PASTE URLS [ONE PER LINE]..."
            value={urls}
            onChange={e => setUrls(e.target.value)}
          />
          <button onClick={addToQueue} className="w-full bg-white/5 text-white py-3 hover:bg-katana hover:text-black border-t border-white/10 font-mono text-xs uppercase tracking-widest flex justify-center items-center gap-2 transition-colors">
            <Plus className="w-4 h-4" /> Inject to Queue
          </button>
        </div>

        {/* Queue List */}
        <div className="lg:col-span-2 bg-armor border border-white/10 flex flex-col min-h-0 relative overflow-hidden">
          {/* Decorative Grid Background */}
          <div className="absolute inset-0 bg-[linear-gradient(rgba(255,255,255,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.02)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none"></div>

          <div className="p-4 border-b border-white/10 flex justify-between items-center bg-black/40 backdrop-blur z-10">
             <div className="flex gap-6 font-mono text-xs">
               <span className="text-steel">TOTAL: <span className="text-white">{progress.total}</span></span>
               <span className="text-steel">SUCCESS: <span className="text-green-500">{progress.completed}</span></span>
               <span className="text-steel">FAILED: <span className="text-katana">{progress.failed}</span></span>
             </div>
             <button onClick={clearQueue} className="text-steel hover:text-katana transition-colors">
               <Trash2 className="w-4 h-4" />
             </button>
          </div>

          <div className="flex-1 overflow-y-auto p-0 z-10 custom-scrollbar">
            <table className="w-full text-left text-sm">
              <thead className="bg-white/5 text-steel font-mono text-xs uppercase tracking-wider border-b border-white/5 sticky top-0">
                <tr>
                  <th className="px-6 py-3 w-32">State</th>
                  <th className="px-6 py-3">Payload Identifier</th>
                  <th className="px-6 py-3 text-right">Data</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/5 font-mono text-xs">
                {queue.map((item) => (
                  <tr key={item.id} className="hover:bg-white/5 transition-colors group">
                    <td className="px-6 py-3">
                      {item.status === 'pending' && <span className="text-steel flex items-center gap-2">WAITING...</span>}
                      {item.status === 'processing' && <span className="text-blue-400 flex items-center gap-2"><Loader2 className="w-3 h-3 animate-spin"/> PROCESSING</span>}
                      {item.status === 'success' && <span className="text-green-500 flex items-center gap-2"><CheckCircle className="w-3 h-3"/> COMPLETE</span>}
                      {item.status === 'failed' && <span className="text-katana flex items-center gap-2"><XCircle className="w-3 h-3"/> FAILURE</span>}
                    </td>
                    <td className="px-6 py-3">
                      <div className="font-medium text-white truncate max-w-xs md:max-w-md group-hover:text-katana transition-colors">
                        {item.result?.title || item.url}
                      </div>
                      {item.result?.error && <div className="text-[10px] text-red-500 mt-1">>> ERR: {item.result.error}</div>}
                    </td>
                    <td className="px-6 py-3 text-right text-steel">
                      {item.result?.wordCount ? `${item.result.wordCount} words` : '-'}
                    </td>
                  </tr>
                ))}
                {queue.length === 0 && (
                  <tr>
                    <td colSpan={3} className="px-6 py-20 text-center">
                      <div className="flex flex-col items-center gap-3 opacity-20">
                         <TerminalSquare className="w-12 h-12" />
                         <span className="font-mono text-sm uppercase tracking-widest">Buffer Empty</span>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

