import React, { useState } from 'react';
import { Play, Copy, Download, Loader2, AlertCircle, Terminal, Cpu } from 'lucide-react';
import { Chapter } from '../types';

export default function SingleExtract() {
  const [url, setUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<Chapter | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleExtract = async () => {
    if (!url) return;
    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const response = await fetch('/api/extract', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url }),
      });

      if (!response.ok) {
        const errData = await response.json();
        throw new Error(errData.message || 'Extraction failed');
      }

      const data = await response.json();
      setResult(data);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = () => {
    if (result) {
      navigator.clipboard.writeText(`${result.title}\n\n${result.content}`);
    }
  };

  const downloadTxt = () => {
    if (!result) return;
    const element = document.createElement("a");
    const file = new Blob([`${result.title}\n\nSource: ${result.url}\n\n${result.content}`], {type: 'text/plain'});
    element.href = URL.createObjectURL(file);
    element.download = `${result.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.txt`;
    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col gap-1 border-l-4 border-katana pl-4">
        <h2 className="text-3xl font-bold text-white tracking-tight uppercase">Single Target Extraction</h2>
        <p className="text-steel font-mono text-sm">Initialize sequence for singular web entity.</p>
      </div>

      <div className="bg-armor border border-white/10 p-1">
        <div className="flex gap-0">
          <div className="flex-1 bg-plate relative group">
            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
              <Terminal className="h-4 w-4 text-steel group-focus-within:text-katana transition-colors" />
            </div>
            <input
              type="url"
              value={url}
              onChange={(e) => setUrl(e.target.value)}
              placeholder="ENTER TARGET URL..."
              className="w-full bg-transparent text-white p-4 pl-12 focus:outline-none font-mono text-sm placeholder:text-gray-700"
            />
          </div>
          <button
            onClick={handleExtract}
            disabled={loading || !url}
            className="bg-katana hover:bg-red-600 text-black px-8 py-4 font-bold uppercase tracking-widest disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2 transition-all hover:shadow-[0_0_15px_#DC2626]"
          >
            {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Play className="w-5 h-5 fill-current" />}
            Execute
          </button>
        </div>
      </div>

      {error && (
        <div className="bg-red-950/30 text-red-400 p-4 border border-red-900/50 flex items-center gap-3 font-mono text-sm">
          <AlertCircle className="w-5 h-5 shrink-0" />
          <p>&gt; ERROR: {error}</p>
        </div>
      )}

      {result && (
        <div className="bg-armor border border-white/10 shadow-2xl overflow-hidden relative">
          <div className="absolute top-0 right-0 p-2 opacity-10">
             <Cpu className="w-24 h-24 text-white" />
          </div>

          <div className="bg-black/40 px-6 py-4 border-b border-white/5 flex justify-between items-center backdrop-blur-sm">
            <div className="z-10">
              <h3 className="font-bold text-white text-lg tracking-wide">{result.title}</h3>
              <p className="text-[10px] text-katana font-mono uppercase tracking-wider">{result.url}</p>
            </div>
            <div className="flex gap-2 z-10">
              <button onClick={copyToClipboard} className="p-2 text-steel hover:text-white hover:bg-white/10 transition-colors border border-transparent hover:border-white/10" title="Copy Buffer">
                <Copy className="w-4 h-4" />
              </button>
              <button onClick={downloadTxt} className="p-2 text-steel hover:text-katana hover:bg-red-950/30 transition-colors border border-transparent hover:border-red-900/50" title="Export Data">
                <Download className="w-4 h-4" />
              </button>
            </div>
          </div>
          <div className="p-8 max-h-[600px] overflow-y-auto custom-scrollbar">
            <pre className="whitespace-pre-wrap font-serif text-lg leading-relaxed text-gray-300 font-light">
              {result.content}
            </pre>
          </div>
        </div>
      )}
    </div>
  );
}

